class Solution {
    public boolean haveConflict(String[] event1, String[] event2) {
        Arrays.sort(event1);
        Arrays.sort(event2);

        for (int i = 0; i < event1.length; i++) {
            for (int j = i + 1; j < event2.length; j++) {
                if (event1[i].compareTo(event2[j]) <= 0) {
                    return true;
                }
            }
        }
        return false;
    }
}
```

